from azure.ai.projects import AgentClient
import re

client = AgentClient.from_azure_project()

def scan_tool_output(tool_call, enterprise_policies):
    output = tool_call.result.content
    violations = []

    # Check for PII patterns
    if re.search(r'\b\d{3}-\d{2}-\d{4}\b', output):
        violations.append('SSN detected')

    # Check approved domains
    approved_domains = enterprise_policies.get('allowed_domains', [])
    for url in re.finditer(r'https?://[^\s]+', output):
        domain = url.group().split('/')[2]
        if domain not in approved_domains:
            violations.append(f'Unapproved domain: {domain}')

    return {'violations': violations, 'clean': len(violations) == 0}

from datetime import datetime, timedelta
from azure.ai.projects.agents import AgentThread

def validate_grounding_freshness(agent_thread: AgentThread, max_age_days: int = 90):
    issues = []
    messages = agent_thread.get_messages()

    for msg in messages:
        if hasattr(msg, 'grounding_data'):
            for citation in msg.grounding_data.citations:
                pub_date = citation.publication_date
                if pub_date:
                    age = (datetime.now() - pub_date).days
                    if age > max_age_days:
                        issues.append({
                            'citation': citation.title,
                            'age_days': age,
                            'max_age': max_age_days
                        })
    return issues

